### 2. 주요 클래스/함수 설계 (권장)

#### 2.1 Entity 계층

```kotlin
// CallEntity.kt - 통화 기본 정보
@Entity
@Table(catalog = "maum", name = "call")
class CallEntity(
    @Id
    @GeneratedValue(generator = "uuid2")
    @GenericGenerator(name = "uuid2", strategy = "uuid2")
    val id: String = "",

    val initiatorUserId: String,          // 통화 시작자
    val receiverUserId: String,           // 통화 수신자
    var status: Int = 0,                  // 0:preparing, 1:active, 2:ended, 3:declined
    var duration: Long = 0,               // 통화 시간(초)

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),

    var endedAt: LocalDateTime? = null,
)

enum class CallStatus(val value: Int) {
    PREPARING(0),
    ACTIVE(1),
    ENDED(2),
    DECLINED(3),
    MISSED(4);

    companion object {
        fun fromValue(value: Int) = entries.first { it.value == value }
    }
}
```

#### 2.2 Repository 계층

```kotlin
// CallRepository.kt
interface CallRepository : JpaRepository<CallEntity, String> {
    fun findByInitiatorUserId(userId: String): List<CallEntity>
    fun findByReceiverUserId(userId: String): List<CallEntity>
    fun findByInitiatorUserIdAndStatus(userId: String, status: Int): List<CallEntity>
    fun findByReceiverUserIdAndStatus(userId: String, status: Int): List<CallEntity>

    @Query("""
        SELECT c FROM CallEntity c
        WHERE (c.initiatorUserId = :userId OR c.receiverUserId = :userId)
        AND c.createdAt >= :since
        ORDER BY c.createdAt DESC
    """)
    fun findRecentCalls(@Param("userId") userId: String, @Param("since") since: LocalDateTime): List<CallEntity>
}
```

#### 2.3 Service 계층

```kotlin
// CallService.kt
@Service
class CallService(
    private val callRepository: CallRepository,
    private val userRepository: UserRepository,
    private val eventPublisher: ApplicationEventPublisher,
) {
    @Transactional
    fun initiateCall(initiatorId: String, receiverId: String): CallEntity {
        // 수신자 존재 확인
        val receiver = userRepository.findById(receiverId)
            .orElseThrow { NotFoundException("User not found: $receiverId") }

        // 통화 생성
        val call = CallEntity(
            initiatorUserId = initiatorId,
            receiverUserId = receiverId,
            status = CallStatus.PREPARING.value,
        )
        val savedCall = callRepository.save(call)

        // 이벤트 발행
        eventPublisher.publishEvent(CallInitiatedEvent(savedCall.id, receiverId))

        return savedCall
    }

    @Transactional
    fun acceptCall(callId: String, userId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NotFoundException("Call not found") }

        require(call.receiverUserId == userId) { "Unauthorized" }
        require(call.status == CallStatus.PREPARING.value) { "Invalid call status" }

        call.status = CallStatus.ACTIVE.value
        val updated = callRepository.save(call)

        eventPublisher.publishEvent(CallAcceptedEvent(callId, call.initiatorUserId))
        return updated
    }

    @Transactional
    fun endCall(callId: String): CallEntity {
        val call = callRepository.findById(callId)
            .orElseThrow { NotFoundException("Call not found") }

        call.status = CallStatus.ENDED.value
        call.endedAt = LocalDateTime.now()
        call.duration = ChronoUnit.SECONDS.between(call.createdAt, call.endedAt).toInt()

        return callRepository.save(call)
    }

    @Transactional(readOnly = true)
    fun getCallHistory(userId: String, limit: Int = 20, offset: Int = 0): List<CallEntity> {
        return callRepository.findRecentCalls(userId, LocalDateTime.now().minusMonths(1))
            .drop(offset)
            .take(limit)
    }
}
```

#### 2.4 gRPC Service (Proto + 구현)

```protobuf
// call_service.proto
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc InitiateCall(InitiateCallRequest) returns (CallResponse);
  rpc AcceptCall(AcceptCallRequest) returns (CallResponse);
  rpc EndCall(EndCallRequest) returns (CallResponse);
  rpc GetCallHistory(GetCallHistoryRequest) returns (GetCallHistoryResponse);
  rpc DeclineCall(DeclineCallRequest) returns (CallResponse);
}

message CallMessage {
  string id = 1;
  string initiator_user_id = 2;
  string receiver_user_id = 3;
  int32 status = 4;
  int32 duration = 5;
  string created_at = 6;
  string ended_at = 7;
}

message InitiateCallRequest {
  string initiator_id = 1;
  string receiver_id = 2;
}

message CallResponse {
  CallMessage call = 1;
}
```

```kotlin
// CallGrpcService.kt
@GrpcService
class CallGrpcService(
    private val callService: CallService,
) : CallServiceGrpc.CallServiceImplBase() {

    override fun initiateCall(
        request: InitiateCallRequest,
        responseObserver: StreamObserver<CallResponse>,
    ) {
        try {
            val call = callService.initiateCall(
                request.initiatorId,
                request.receiverId
            )
            responseObserver.onNext(
                CallResponse.newBuilder()
                    .setCall(call.toProto())
                    .build()
            )
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }

    override fun endCall(
        request: EndCallRequest,
        responseObserver: StreamObserver<CallResponse>,
    ) {
        try {
            val call = callService.endCall(request.callId)
            responseObserver.onNext(
                CallResponse.newBuilder()
                    .setCall(call.toProto())
                    .build()
            )
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }
}
```

#### 2.5 GraphQL 계층

```graphql
# call.graphqls
type Call {
    id: ID!
    initiator: SimpleUser!
    receiver: SimpleUser!
    status: CallStatus!
    duration: Int!
    createdAt: String!
    endedAt: String
}

enum CallStatus {
    PREPARING
    ACTIVE
    ENDED
    DECLINED
    MISSED
}

input InitiateCallInput {
    receiverId: ID!
}

extend type Query {
    callHistory(limit: Int, offset: Int): [Call!]!
    ongoingCall: Call
}

extend type Mutation {
    initiateCall(input: InitiateCallInput!): Call!
    acceptCall(callId: ID!): Call!
    declineCall(callId: ID!): Call!
    endCall(callId: ID!): Call!
}
```

```kotlin
// CallController.kt
@Controller
class CallController(
    private val callService: CallGraphQLService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun callHistory(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<CallResponse> {
        val response = callService.getCallHistory(userId, limit ?: 20, offset ?: 0)
        return response.callsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun initiateCall(
        @UserId userId: String,
        @Argument input: InitiateCallInput,
    ): CallResponse {
        val response = callService.initiateCall(userId, input.receiverId)
        return response.call.toResponse()
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun acceptCall(
        @UserId userId: String,
        @Argument callId: String,
    ): CallResponse {
        val response = callService.acceptCall(callId)
        return response.call.toResponse()
    }
}
```

```kotlin
// CallGraphQLService.kt - gRPC 클라이언트
@Service
class CallGraphQLService {
    @GrpcClient("call-grpc")
    private lateinit var stub: CallServiceGrpc.CallServiceBlockingStub

    fun initiateCall(userId: String, receiverId: String): CallResponse {
        val request = InitiateCallRequest.newBuilder()
            .setInitiatorId(userId)
            .setReceiverId(receiverId)
            .build()
        return try {
            stub.initiateCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("CALL_ERROR", e.status.description)
        }
    }

    fun acceptCall(callId: String): CallResponse {
        val request = AcceptCallRequest.newBuilder()
            .setCallId(callId)
            .build()
        return try {
            stub.acceptCall(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException("CALL_ERROR", e.status.description)
        }
    }
}
```

