### 5. 권장 추가 구현

```kotlin
// 1. 상태 머신
enum class CallState {
    PREPARING,
    ACTIVE,
    ENDED,
    DECLINED,
    MISSED;

    fun canTransitionTo(next: CallState): Boolean =
        when (this) {
            PREPARING -> next in listOf(ACTIVE, DECLINED, MISSED)
            ACTIVE -> next in listOf(ENDED, MISSED)
            else -> false
        }
}

// 2. 타임아웃 처리
@Component
class CallTimeoutScheduler(
    private val callService: CallService,
) {
    @Scheduled(fixedDelay = 60000) // 1분마다
    fun cleanupExpiredCalls() {
        val expiredCalls = callRepository.findExpiredPreparingCalls(
            LocalDateTime.now().minusMinutes(2)
        )
        expiredCalls.forEach { call ->
            call.status = CallStatus.MISSED.value
            callRepository.save(call)
        }
    }
}

// 3. Redis 캐싱
@Service
class CallCacheService(
    private val redisTemplate: RedisTemplate<String, CallEntity>,
) {
    fun cacheActiveCall(callId: String, call: CallEntity) {
        redisTemplate.opsForValue().set("call:$callId", call, Duration.ofHours(2))
    }

    fun getActiveCall(callId: String): CallEntity? =
        redisTemplate.opsForValue().get("call:$callId")
}
```

